import React, { useState, useEffect, useCallback, useMemo } from 'react';
import type { 
    MockQuestion, 
    SingleChoiceQuestion, 
    MultiChoiceQuestion, 
    MatchingQuestion, 
    DropdownQuestion, 
    ScenarioQuestion,
    UserAnswer,
    UserAnswerValue,
    MatchingAnswer,
    DropdownAnswer
} from '../types.ts';
import { Clock, Loader, ArrowLeft, CheckCircle, Layers } from './Icons.tsx';

interface MockExamPageProps {
  questions: MockQuestion[];
  onFinishExam: (score: number, totalMarks: number, userAnswers: UserAnswer[], questions: MockQuestion[]) => void;
  onGoHome: () => void;
}

const EXAM_DURATION = 7200; // 2 hours in seconds

// Helper to shuffle arrays
const shuffleArray = <T,>(array: T[]): T[] => {
  return [...array].sort(() => Math.random() - 0.5);
};

// --- Sub-Components for Question Types ---

const SingleChoice: React.FC<{ 
    q: SingleChoiceQuestion; 
    answer: string | undefined; 
    onAnswer: (questionId: string, answer: string) => void; 
}> = ({ q, answer, onAnswer }) => {
    return (
        <div className="space-y-3">
            {q.options.map(opt => (
                <button
                    key={opt}
                    onClick={() => onAnswer(q.id, opt)}
                    className={`w-full text-left p-4 rounded-xl border-2 transition-all duration-200 flex items-center ${
                        answer === opt 
                          ? 'border-primary bg-primary-light text-primary font-semibold' 
                          : 'border-slate-200 dark:border-slate-700 hover:border-primary/50 bg-white dark:bg-slate-800 dark:text-slate-200'
                    }`}
                >
                    <div className={`w-5 h-5 rounded-full border-2 mr-4 flex items-center justify-center flex-shrink-0 ${
                        answer === opt ? 'border-primary' : 'border-slate-300 dark:border-slate-500'
                    }`}>
                        {answer === opt && <div className="w-2.5 h-2.5 rounded-full bg-primary" />}
                    </div>
                    {opt}
                </button>
            ))}
        </div>
    );
};

const MultiChoice: React.FC<{ 
    q: MultiChoiceQuestion; 
    answer: string[] | undefined; 
    onAnswer: (questionId: string, answer: string[]) => void; 
}> = ({ q, answer, onAnswer }) => {
    const currentAns = answer || [];

    const toggleOption = (opt: string) => {
        const exists = currentAns.includes(opt);
        let newAns;
        if (exists) newAns = currentAns.filter(x => x !== opt);
        else newAns = [...currentAns, opt];

        onAnswer(q.id, newAns);
    };

    return (
        <div className="space-y-3">
            <p className="text-sm font-bold text-primary uppercase mb-2">Select {q.correctAnswers.length} options</p>
            {q.options.map(opt => {
                const isSelected = currentAns.includes(opt);
                return (
                  <button
                      key={opt}
                      onClick={() => toggleOption(opt)}
                      className={`w-full text-left p-4 rounded-xl border-2 transition-all duration-200 flex items-center ${
                          isSelected 
                              ? 'border-primary bg-primary-light text-primary font-semibold' 
                              : 'border-slate-200 dark:border-slate-700 hover:border-primary/50 bg-white dark:bg-slate-800 dark:text-slate-200'
                      }`}
                  >
                      <div className={`w-5 h-5 rounded border-2 mr-4 flex items-center justify-center flex-shrink-0 ${
                          isSelected ? 'border-primary bg-primary text-white' : 'border-slate-300 dark:border-slate-500'
                      }`}>
                          {isSelected && <CheckCircle className="w-4 h-4 text-white" />}
                      </div>
                      {opt}
                  </button>
                );
            })}
        </div>
    );
};

const Matching: React.FC<{ 
    q: MatchingQuestion; 
    answer: MatchingAnswer | undefined; 
    onAnswer: (questionId: string, answer: MatchingAnswer) => void; 
}> = ({ q, answer, onAnswer }) => {
    const currentAns = answer || {};
    // useMemo is safe here
    const rightOptions = useMemo(() => shuffleArray(q.pairs.map(p => p.right)), [q]);

    const handleChange = (leftItem: string, selectedRight: string) => {
        onAnswer(q.id, { ...currentAns, [leftItem]: selectedRight });
    };

    return (
        <div className="space-y-4">
            <p className="text-sm text-text-light mb-2">Match the items on the left with the correct description on the right.</p>
            {q.pairs.map((pair, idx) => (
                <div key={idx} className="flex flex-col sm:flex-row sm:items-center gap-4 p-4 bg-slate-50 dark:bg-slate-800 rounded-lg border border-border-light">
                    <div className="font-semibold text-dark flex-1">{pair.left}</div>
                    <div className="hidden sm:block text-slate-400 dark:text-slate-500">→</div>
                    <div className="flex-1">
                        <select
                            className="w-full p-2 rounded border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-700 dark:text-white"
                            value={currentAns[pair.left] || ''}
                            onChange={(e) => handleChange(pair.left, e.target.value)}
                        >
                            <option value="">Select a match...</option>
                            {rightOptions.map((opt, i) => (
                                <option key={i} value={opt}>{opt}</option>
                            ))}
                        </select>
                    </div>
                </div>
            ))}
        </div>
    );
};

const Dropdown: React.FC<{ 
    q: DropdownQuestion; 
    answer: DropdownAnswer | undefined; 
    onAnswer: (questionId: string, answer: DropdownAnswer) => void; 
}> = ({ q, answer, onAnswer }) => {
    const currentAns = answer || {};

    const handleChange = (index: number, val: string) => {
        onAnswer(q.id, { ...currentAns, [index]: val });
    };

    return (
        <div className="leading-loose text-lg text-dark">
            {q.parts.map((part, idx) => {
                if (part.text) return <span key={idx} className="mr-2">{part.text}</span>;
                if (part.options) {
                    return (
                        <select
                            key={idx}
                            value={currentAns[idx] || ''}
                            onChange={(e) => handleChange(idx, e.target.value)}
                            className="inline-block mx-2 p-1 border-b-2 border-primary bg-primary-light/20 dark:bg-primary-light/10 focus:outline-none rounded text-base font-semibold text-primary dark:text-primary-light dark:bg-slate-700"
                        >
                            <option value="">(Select...)</option>
                            {part.options.map(opt => <option key={opt} value={opt} className="text-dark dark:text-white dark:bg-slate-800">{opt}</option>)}
                        </select>
                    );
                }
                return null;
            })}
        </div>
    );
};

const Scenario: React.FC<{ 
    q: ScenarioQuestion; 
    userAnswers: UserAnswer[]; 
    onAnswer: (questionId: string, answer: UserAnswerValue) => void; 
}> = ({ q, userAnswers, onAnswer }) => {
    return (
        <div className="space-y-8">
            <div className="bg-slate-100 dark:bg-slate-800 p-6 rounded-xl border-l-4 border-primary">
                <h3 className="text-lg font-bold text-dark mb-2 flex items-center gap-2">
                    <Layers className="w-5 h-5 text-primary" />
                    Scenario
                </h3>
                <p className="text-dark/80 leading-relaxed whitespace-pre-wrap">{q.scenario}</p>
            </div>
            <div className="space-y-10">
                {q.questions.map((subQ, idx) => {
                    const ansEntry = userAnswers.find(a => a.questionId === subQ.id);
                    return (
                        <div key={subQ.id} className="border-t pt-6 border-slate-200 dark:border-slate-700">
                            <div className="flex items-baseline justify-between mb-4">
                                <h4 className="font-bold text-dark text-lg">Task {String.fromCharCode(97 + idx)}</h4>
                                <span className="text-xs font-bold px-2 py-1 bg-slate-200 dark:bg-slate-700 rounded text-slate-600 dark:text-slate-300">{subQ.marks} Mark{subQ.marks > 1 ? 's' : ''}</span>
                            </div>
                            <p className="text-dark mb-4 font-medium">{subQ.question}</p>
                            {subQ.type === 'single' && <SingleChoice key={subQ.id} q={subQ as SingleChoiceQuestion} answer={ansEntry?.answer as string} onAnswer={onAnswer} />}
                            {subQ.type === 'multi' && <MultiChoice key={subQ.id} q={subQ as MultiChoiceQuestion} answer={ansEntry?.answer as string[]} onAnswer={onAnswer} />}
                            {subQ.type === 'matching' && <Matching key={subQ.id} q={subQ as MatchingQuestion} answer={ansEntry?.answer as MatchingAnswer} onAnswer={onAnswer} />}
                            {subQ.type === 'dropdown' && <Dropdown key={subQ.id} q={subQ as DropdownQuestion} answer={ansEntry?.answer as DropdownAnswer} onAnswer={onAnswer} />}
                        </div>
                    );
                })}
            </div>
        </div>
    );
};


