const MockExamPage: React.FC<MockExamPageProps> = ({ questions, onFinishExam, onGoHome }) => {
  const [examState, setExamState] = useState<'intro' | 'active' | 'submitting'>('intro');
  const [examQuestions, setExamQuestions] = useState<MockQuestion[]>([]);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [userAnswers, setUserAnswers] = useState<UserAnswer[]>([]);
  const [timeLeft, setTimeLeft] = useState(EXAM_DURATION);
  const [showQuitConfirm, setShowQuitConfirm] = useState(false);

  // Initialize Exam with Randomization
  useEffect(() => {
    // Randomize Section A (Objective Questions) to simulate exam swapping
    const sectionA = shuffleArray(questions.filter(q => q.type !== 'scenario'));

    // Keep Section B (Scenarios) randomized or fixed as per need
    const sectionB = shuffleArray(questions.filter(q => q.type === 'scenario'));

    const fullExam = [...sectionA, ...sectionB];
    setExamQuestions(fullExam);
  }, [questions]);

  const calculateScore = useCallback(() => {
      let totalScore = 0;
      let totalMarks = 0;

      examQuestions.forEach(q => {
          if (q.type === 'scenario') {
              const scenarioQ = q as ScenarioQuestion;
              scenarioQ.questions.forEach(subQ => {
                  totalMarks += subQ.marks;
                  // Logic to check subQ answer
                  const ansEntry = userAnswers.find(a => a.questionId === subQ.id);
                  if (ansEntry) {
                      totalScore += getQuestionScore(subQ, ansEntry.answer);
                  }
              });
          } else {
              totalMarks += q.marks;
              const ansEntry = userAnswers.find(a => a.questionId === q.id);
              if (ansEntry) {
                  totalScore += getQuestionScore(q, ansEntry.answer);
              }
          }
      });
      return { totalScore, totalMarks };
  }, [examQuestions, userAnswers]);

  const getQuestionScore = (question: MockQuestion, answer: UserAnswerValue): number => {
      if (!answer) return 0;

      switch (question.type) {
          case 'single': {
              return (answer as string) === question.correctAnswer ? question.marks : 0;
          }
          case 'multi': {
              const userArr = answer as string[];
              const correctArr = (question as MultiChoiceQuestion).correctAnswers;
              // ACCA BT: usually 2 marks. 0 if not fully correct.
              if (userArr.length !== correctArr.length) return 0;
              const allCorrect = userArr.every(val => correctArr.includes(val));
              return allCorrect ? question.marks : 0;
          }
          case 'matching': {
              const userMap = answer as MatchingAnswer;
              const pairs = (question as MatchingQuestion).pairs;
              // Check if all pairs match
              let allCorrect = true;
              pairs.forEach(pair => {
                  if (userMap[pair.left] !== pair.right) allCorrect = false;
              });
              return allCorrect ? question.marks : 0;
          }
          case 'dropdown': {
              const userMap = answer as DropdownAnswer;
              const parts = (question as DropdownQuestion).parts;
              let allCorrect = true;
              let partIndex = 0;
              parts.forEach((part) => {
                  if (part.options) {
                       if (userMap[partIndex] !== part.correctAnswer) allCorrect = false;
                  }
                  partIndex++;
              });
              return allCorrect ? question.marks : 0;
          }
          default: return 0;
      }
  };

  const finishExam = useCallback(() => {
    setExamState('submitting');
    const { totalScore, totalMarks } = calculateScore();

    setTimeout(() => {
        onFinishExam(totalScore, totalMarks, userAnswers, examQuestions);
    }, 1000);
  }, [calculateScore, onFinishExam, userAnswers, examQuestions]);


  // Modified timer logic to avoid side-effects in state updater
  useEffect(() => {
    if (examState !== 'active' || showQuitConfirm) return;

    const timer = setInterval(() => {
        setTimeLeft(prev => {
            if (prev <= 0) return 0;
            return prev - 1;
        });
    }, 1000);

    return () => clearInterval(timer);
  }, [examState, showQuitConfirm]);

  // Watch timeLeft to trigger finish
  useEffect(() => {
      if (examState === 'active' && timeLeft === 0) {
          finishExam();
      }
  }, [timeLeft, examState, finishExam]);

  const handleStartExam = () => setExamState('active');

  const handleAnswer = (questionId: string, answer: UserAnswerValue) => {
    setUserAnswers(prev => {
        const idx = prev.findIndex(a => a.questionId === questionId);
        if (idx >= 0) {
            const newArr = [...prev];
            newArr[idx] = { questionId, answer };
            return newArr;
        }
        return [...prev, { questionId, answer }];
    });
  };

  const formatTime = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    const s = seconds % 60;
    return `${h}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };


  if (examState === 'intro') {
      return (
          <div className="text-center p-8 card max-w-2xl mx-auto mt-8">
