             <div className="flex items-center gap-4">
                 <button onClick={() => setShowQuitConfirm(true)} className="text-sm font-semibold text-slate-500 hover:text-red-500 flex items-center gap-1">
                     <ArrowLeft className="w-4 h-4" /> Quit
                 </button>
                 <span className="text-sm font-bold text-dark">Q {currentQuestionIndex + 1} / {examQuestions.length}</span>
             </div>
             <div className={`font-mono font-bold text-lg ${timeLeft < 300 ? 'text-red-600 animate-pulse' : 'text-dark'}`}>
                 {formatTime(timeLeft)}
             </div>
        </div>

        {/* Progress Bar */}
        <div className="w-full bg-slate-200 dark:bg-slate-700 h-1.5 fixed top-0 left-0 z-30">
             <div className="bg-primary h-full transition-all duration-300" style={{ width: `${progress}%` }} />
        </div>

        {/* Question Card */}
        <div className="card p-6 sm:p-8 shadow-xl relative">
             {currentQ.type !== 'scenario' && (
                 <div className="flex justify-between items-start mb-6">
                     <h3 className="text-xl font-bold text-dark leading-snug">{currentQ.question}</h3>
                     <span className="ml-4 shrink-0 text-xs font-bold px-2 py-1 bg-slate-100 dark:bg-slate-700 rounded text-slate-500 dark:text-slate-300 border border-slate-200 dark:border-slate-600">{currentQ.marks} Marks</span>
                 </div>
             )}

             <div className="mb-8">
                 {currentQ.type === 'single' && <SingleChoice key={currentQ.id} q={currentQ as SingleChoiceQuestion} answer={currentAnsEntry?.answer as string} onAnswer={handleAnswer} />}
                 {currentQ.type === 'multi' && <MultiChoice key={currentQ.id} q={currentQ as MultiChoiceQuestion} answer={currentAnsEntry?.answer as string[]} onAnswer={handleAnswer} />}
                 {currentQ.type === 'matching' && <Matching key={currentQ.id} q={currentQ as MatchingQuestion} answer={currentAnsEntry?.answer as MatchingAnswer} onAnswer={handleAnswer} />}
