                    <div className="flex gap-4 justify-center">
                        <button onClick={() => setShowQuitConfirm(false)} className="btn-secondary">Cancel</button>
                        <button onClick={onGoHome} className="px-6 py-2 bg-red-500 text-white rounded-xl font-semibold hover:bg-red-600">Quit</button>
                    </div>
                </div>
            </div>
        )}
    </div>
  );
};

export default MockExamPage;
